-- ============================================================
-- Migration 006: Add subtopic column and generate SAT questions
-- Run this in Supabase SQL Editor
-- ============================================================

-- 1. Add subtopic column
ALTER TABLE sat_questions ADD COLUMN IF NOT EXISTS subtopic text;

-- 2. Index for efficient diagnostic queries
CREATE INDEX IF NOT EXISTS idx_sat_questions_subtopic ON sat_questions(subtopic);
CREATE INDEX IF NOT EXISTS idx_sat_questions_category_subtopic ON sat_questions(category, subtopic);

-- 3. Backfill existing questions with subtopics based on content heuristics
-- Algebra subtopics
UPDATE sat_questions SET subtopic = 'linear-equations' WHERE category = 'Algebra' AND subtopic IS NULL AND (question ILIKE '%linear%' OR question ILIKE '%slope%' OR question ILIKE '%y = mx%' OR question ILIKE '%y-intercept%') AND id IN (SELECT id FROM sat_questions WHERE category = 'Algebra' AND subtopic IS NULL LIMIT 20);
UPDATE sat_questions SET subtopic = 'quadratics' WHERE category = 'Algebra' AND subtopic IS NULL AND (question ILIKE '%quadratic%' OR question ILIKE '%factor%' OR question ILIKE '%x²%' OR question ILIKE '%parabola%') AND id IN (SELECT id FROM sat_questions WHERE category = 'Algebra' AND subtopic IS NULL LIMIT 20);
UPDATE sat_questions SET subtopic = 'systems-of-equations' WHERE category = 'Algebra' AND subtopic IS NULL AND (question ILIKE '%system%' OR question ILIKE '%simultaneous%' OR question ILIKE '%two equations%') AND id IN (SELECT id FROM sat_questions WHERE category = 'Algebra' AND subtopic IS NULL LIMIT 20);
UPDATE sat_questions SET subtopic = 'functions' WHERE category = 'Algebra' AND subtopic IS NULL AND (question ILIKE '%f(x)%' OR question ILIKE '%function%' OR question ILIKE '%domain%' OR question ILIKE '%range%') AND id IN (SELECT id FROM sat_questions WHERE category = 'Algebra' AND subtopic IS NULL LIMIT 20);
UPDATE sat_questions SET subtopic = 'inequalities' WHERE category = 'Algebra' AND subtopic IS NULL AND (question ILIKE '%inequalit%' OR question ILIKE '%greater than%' OR question ILIKE '%less than%') AND id IN (SELECT id FROM sat_questions WHERE category = 'Algebra' AND subtopic IS NULL LIMIT 20);
-- Catch remaining algebra questions
UPDATE sat_questions SET subtopic = 'linear-equations' WHERE category = 'Algebra' AND subtopic IS NULL;

-- Reading subtopics
UPDATE sat_questions SET subtopic = 'main-idea' WHERE category = 'Reading Comprehension' AND subtopic IS NULL AND (question ILIKE '%main idea%' OR question ILIKE '%central%' OR question ILIKE '%primarily%' OR question ILIKE '%purpose%') AND id IN (SELECT id FROM sat_questions WHERE category = 'Reading Comprehension' AND subtopic IS NULL LIMIT 25);
UPDATE sat_questions SET subtopic = 'vocabulary-in-context' WHERE category = 'Reading Comprehension' AND subtopic IS NULL AND (question ILIKE '%word%mean%' OR question ILIKE '%most nearly%' OR question ILIKE '%closest in meaning%' OR question ILIKE '%as used in%') AND id IN (SELECT id FROM sat_questions WHERE category = 'Reading Comprehension' AND subtopic IS NULL LIMIT 25);
UPDATE sat_questions SET subtopic = 'evidence-based' WHERE category = 'Reading Comprehension' AND subtopic IS NULL AND (question ILIKE '%evidence%' OR question ILIKE '%support%' OR question ILIKE '%best describes%' OR question ILIKE '%according to%') AND id IN (SELECT id FROM sat_questions WHERE category = 'Reading Comprehension' AND subtopic IS NULL LIMIT 25);
UPDATE sat_questions SET subtopic = 'inference' WHERE category = 'Reading Comprehension' AND subtopic IS NULL;

-- Grammar subtopics
UPDATE sat_questions SET subtopic = 'punctuation' WHERE category = 'Grammar' AND subtopic IS NULL AND (question ILIKE '%comma%' OR question ILIKE '%semicolon%' OR question ILIKE '%colon%' OR question ILIKE '%punctuat%' OR question ILIKE '%apostrophe%') AND id IN (SELECT id FROM sat_questions WHERE category = 'Grammar' AND subtopic IS NULL LIMIT 20);
UPDATE sat_questions SET subtopic = 'subject-verb-agreement' WHERE category = 'Grammar' AND subtopic IS NULL AND (question ILIKE '%verb%' OR question ILIKE '%tense%' OR question ILIKE '%agreement%' OR question ILIKE '%subject%') AND id IN (SELECT id FROM sat_questions WHERE category = 'Grammar' AND subtopic IS NULL LIMIT 20);
UPDATE sat_questions SET subtopic = 'sentence-structure' WHERE category = 'Grammar' AND subtopic IS NULL AND (question ILIKE '%sentence%' OR question ILIKE '%fragment%' OR question ILIKE '%run-on%' OR question ILIKE '%clause%' OR question ILIKE '%combine%') AND id IN (SELECT id FROM sat_questions WHERE category = 'Grammar' AND subtopic IS NULL LIMIT 20);
UPDATE sat_questions SET subtopic = 'transitions' WHERE category = 'Grammar' AND subtopic IS NULL AND (question ILIKE '%transition%' OR question ILIKE '%however%' OR question ILIKE '%therefore%' OR question ILIKE '%logical%' OR question ILIKE '%connect%') AND id IN (SELECT id FROM sat_questions WHERE category = 'Grammar' AND subtopic IS NULL LIMIT 20);
UPDATE sat_questions SET subtopic = 'pronoun-clarity' WHERE category = 'Grammar' AND subtopic IS NULL;

-- Data & Statistics subtopics
UPDATE sat_questions SET subtopic = 'tables-and-graphs' WHERE category = 'Data & Statistics' AND subtopic IS NULL AND (question ILIKE '%table%' OR question ILIKE '%graph%' OR question ILIKE '%chart%' OR question ILIKE '%bar%' OR question ILIKE '%display%') AND id IN (SELECT id FROM sat_questions WHERE category = 'Data & Statistics' AND subtopic IS NULL LIMIT 25);
UPDATE sat_questions SET subtopic = 'probability' WHERE category = 'Data & Statistics' AND subtopic IS NULL AND (question ILIKE '%probabilit%' OR question ILIKE '%chance%' OR question ILIKE '%likely%' OR question ILIKE '%random%') AND id IN (SELECT id FROM sat_questions WHERE category = 'Data & Statistics' AND subtopic IS NULL LIMIT 25);
UPDATE sat_questions SET subtopic = 'scatterplots' WHERE category = 'Data & Statistics' AND subtopic IS NULL AND (question ILIKE '%scatter%' OR question ILIKE '%correlation%' OR question ILIKE '%best fit%' OR question ILIKE '%trend%' OR question ILIKE '%regression%') AND id IN (SELECT id FROM sat_questions WHERE category = 'Data & Statistics' AND subtopic IS NULL LIMIT 25);
UPDATE sat_questions SET subtopic = 'mean-median-mode' WHERE category = 'Data & Statistics' AND subtopic IS NULL;

